import anthropic

def detect_parallel_conflicts(message):
    if not message.tool_use:
        return False

    tools = message.tool_use
    resources = {}
    for tool in tools:
        if tool.name in ['get_user_data', 'update_user_settings']:
            user_id = tool.input.get('user_id')
            if user_id in resources:
                return {'conflict': True, 'resource': 'user_id', 'tools': [resources[user_id], tool.name]}
            resources[user_id] = tool.name
    return False

def trace_cascading_errors(messages):
    errors = []
    for i, msg in enumerate(messages):
        if msg.tool_use:
            for tool in msg.tool_use:
                if tool.name == 'get_user_details':
                    prev_msgs = messages[:i]
                    user_id = tool.input.get('user_id')
                    if not any('list_users' in m.content[0].text for m in prev_msgs):
                        errors.append({
                            'type': 'cascading_failure',
                            'tool': tool.name,
                            'missing_dependency': 'list_users',
                            'message_index': i
                        })
    return errors

function detectComputerUseOverlap(claudeResponse: any): boolean {
  if (!claudeResponse.tool_use) return false;

  const screenTargets: Record<string, string[]> = {};

  for (const tool of claudeResponse.tool_use) {
    if (tool.name === 'computer_use') {
      const target = tool.input?.targetSelector || tool.input?.command;
      if (target) {
        if (screenTargets[target]) {
          return {
            conflict: true,
            target,
            agents: [...screenTargets[target], tool.id]
          };
        }
        screenTargets[target] = [tool.id];
      }
    }
  }
  return false;
}

